const items = $input.all();
const today = DateTime.now().toFormat('yyyy-MM-dd');

if (!items || items.length === 0) {
  return [{
    json: {
      message: ':white_check_mark: *CS Ticket Aging Report -- ' + today + '*\nNo accounts with aging open/pending tickets today. Great work!'
    }
  }];
}

const lines = items.map(function(item) {
  const t = item.json;
  const oldest = t.oldest_ticket_date ? String(t.oldest_ticket_date).substring(0, 10) : 'N/A';
  const total = Number(t.open_ticket_count) || 0;
  const ticketWord = total === 1 ? 'ticket' : 'tickets';
  return '*' + t.account_name + '* -- ' + total + ' ' + ticketWord + ' | Oldest: ' + oldest + ' | open: ' + (Number(t.open_count) || 0) + ', pending: ' + (Number(t.pending_count) || 0);
});

const message =
  ':ticket: *CS Ticket Aging Report -- ' + today + '*\n' +
  'Accounts with open/pending tickets older than 7 days:\n\n' +
  lines.join('\n') +
  '\n\n_Total accounts affected: ' + items.length + '_';

return [{ json: { message: message } }];
